//! FFI bindings to libquicr C wrapper
//!
//! This module contains the raw FFI bindings generated by bindgen.
//! These are not meant to be used directly - use the safe wrappers instead.

#![allow(non_upper_case_globals)]
#![allow(non_camel_case_types)]
#![allow(non_snake_case)]
#![allow(dead_code)]
#![allow(missing_docs)] // don't expect bindgen to produce docs
#![allow(clippy::all)]

// For no_std support, we need to provide our own c_* types
#[cfg(not(feature = "std"))]
pub use core::ffi::{c_char, c_int, c_long, c_uchar, c_uint, c_ulong, c_ushort, c_void};

#[cfg(feature = "std")]
pub use std::ffi::{c_char, c_int, c_long, c_uchar, c_uint, c_ulong, c_ushort, c_void};

include!(concat!(env!("OUT_DIR"), "/bindings.rs"));
